            boolean meet = pAR.getMeetOrSlice() ==
                SVGPreserveAspectRatio.SVG_MEETORSLICE_MEET;
            return getPreserveAspectRatioTransform(vb, align, meet, w, h);
        } catch (LiveAttributeException ex) {
